INSERT INTO `emailtemplates` (`id`, `language_id`, `title`, `subject`, `content`, `status`, `remember_token`, `created_at`, `updated_at`) VALUES
(1, 2, 'Trade25 : Forgot Password Email', 'Trade25 : Please reset your password', '<title></title>\r\n<meta charset=\"UTF-8\"><meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Outfit:wght@100;200;300;400;500;600;700;800;900&amp;display=swap\" rel=\"stylesheet\" />\r\n<table align=\"center\" cellpadding=\"0\" cellspacing=\"0\" width=\"800px\">\r\n	<tbody><!-- Top Image -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><img alt=\"top-image\" src=\"{{$graphic_image}}\" style=\"display: block;\" /></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Logo -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFF7D5\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 40px;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><a href=\"javascript:void(0)\" style=\"display: block;\" target=\"_blank\"><img alt=\"top-image\" src=\"{{$logo}}\" style=\"display: block;\" /> </a></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Details -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 32px 40px; border-bottom: 2px solid #F6F5EF;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\">\r\n						<h2 style=\"font-size: 42px; line-height: 60px; font-weight: 500; color: #000000; margin: 0; padding: 0 0 32px;\">Welcome !</h2>\r\n						</td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"left\">\r\n						<h5 style=\"font-size: 24px; line-height: 36px; font-weight: 500; color: #000000; margin: 0; padding: 0 0 8px;\">Hello<span style=\"font-size:20px;\"> <span style=\"font-size:18px;\">{{$name}}</span></span></h5>\r\n\r\n						<p style=\"font-size: 20px; line-height: 30px; font-weight: 300; letter-spacing: 0.04em; color: #000000; margin: 0; padding: 0 0 32px;\"><span style=\"font-size:14px;\">Your password has been reset successfully, Please find login details below.</span></p>\r\n						<span style=\"font-size:14px;\"><span style=\"line-height: 27px; font-weight: 300; color: rgb(0, 0, 0); margin: 0px; padding: 0px 0px 16px; display: block;\">Here&#39;s your login information:</span></span></td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"left\">\r\n						<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n							<tbody>\r\n								<tr>\r\n									<td align=\"left\"><span style=\"font-size:14px;\"><span align=\"left\" style=\"line-height: 21px; font-weight: 300; color: rgb(0, 0, 0); display: inline-block; margin: 0px 57px 0px 0px;\">Email :</span> <span align=\"left\" style=\"margin: 0px; line-height: 24px; font-weight: 500; color: rgb(0, 0, 0); display: inline-block;\">{{$email}}</span></span></td>\r\n								</tr>\r\n								<tr>\r\n									<td height=\"16px\">&nbsp;</td>\r\n								</tr>\r\n								<tr>\r\n									<td align=\"left\"><span style=\"font-size:20px;\"><span style=\"font-size:14px;\"><span align=\"left\" style=\"line-height: 21px; font-weight: 300; color: rgb(0, 0, 0); display: inline-block; margin: 0px 32px 0px 0px;\">Password :</span> <span align=\"left\" style=\"margin: 0px; line-height: 24px; font-weight: 500; color: rgb(0, 0, 0); display: inline-block;\">{{$password}}</span></span><br />\r\n									<br />\r\n									<span style=\"font-size:14px;\">Best regards,<br />\r\n									Trade25 team</span></span></td>\r\n								</tr>\r\n							</tbody>\r\n						</table>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Footer -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 32px 40px;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" style=\"padding: 0 0 22px;\"><span style=\"display: inline-block;\"><a href=\"{{$settingfacebook}}\" style=\"text-decoration: none; vertical-align: middle; margin: 0 23px 0 0; text-align: center; display: inline-block;\" target=\"_blank\"><img alt=\"linkedIn\" src=\"{{$facebook_logo}}\" style=\"vertical-align: middle;\" /> </a> <a href=\"{{$settingtwitter}}\" style=\"text-decoration: none; vertical-align: middle; margin: 0 23px 0 0; text-align: center; display: inline-block;\" target=\"_blank\"> <img alt=\"twitter\" src=\"{{$in_logo}}\" style=\"vertical-align: middle;\" /> </a> <a href=\"{{$settinginstagram}}\" style=\"text-decoration: none; vertical-align: middle; margin: 0; text-align: center; display: inline-block;\" target=\"_blank\"> <img alt=\"instagram\" src=\"{{$insta_logo}}\" style=\"vertical-align: middle;\" /> </a> </span></td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"center\">\r\n						<p style=\"font-size: 14px; line-height: 21px; font-weight: 300; color: #000000; margin: 0;\">Get in touch with us at<a href=\"mailto:info@trade25.com\" style=\"margin: 0; font-size: 16px; line-height: 24px; font-weight: 500; color: #183951; margin-left: 4px; display: inline-block; text-decoration: none;\">info@trade25.com</a></p>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Bottom Image -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><img alt=\"top-image\" src=\"{{$graphic_image}}\" style=\"display: block;\" /></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>', 1, NULL, '2022-07-05 05:06:47', '2023-08-10 06:31:55'),
(2, 2, 'Only Dance : Instructor Request', 'OnlyDance : Instructor Request Sent', '<link href=\"https://fonts.googleapis.com/css?family=Montserrat\" rel=\"stylesheet\" type=\"text/css\" />\r\n<style id=\"media-query\" type=\"text/css\">body {\r\nmargin: 0;\r\npadding: 0; }\r\ntable, tr, td {\r\nvertical-align: top;\r\nborder-collapse: collapse; }\r\n.ie-browser table, .mso-container table {\r\ntable-layout: fixed; }\r\n* {\r\nline-height: inherit; }\r\na[x-apple-data-detectors=true] {\r\ncolor: inherit !important;\r\ntext-decoration: none !important; }\r\n[owa] .img-container div, [owa] .img-container button {\r\ndisplay: block !important; }\r\n[owa] .fullwidth button {\r\nwidth: 100% !important; }\r\n[owa] .block-grid .col {\r\ndisplay: table-cell;\r\nfloat: none !important;\r\nvertical-align: top; }\r\n.ie-browser .num12, .ie-browser .block-grid, [owa] .num12, [owa] .block-grid {\r\nwidth: 600px !important; }\r\n.ExternalClass, .ExternalClass p, .ExternalClass span, .ExternalClass font, .ExternalClass td, .ExternalClass div {\r\nline-height: 100%; }\r\n.ie-browser .mixed-two-up .num4, [owa] .mixed-two-up .num4 {\r\nwidth: 200px !important; }\r\n.ie-browser .mixed-two-up .num8, [owa] .mixed-two-up .num8 {\r\nwidth: 400px !important; }\r\n.ie-browser .block-grid.two-up .col, [owa] .block-grid.two-up .col {\r\nwidth: 300px !important; }\r\n.ie-browser .block-grid.three-up .col, [owa] .block-grid.three-up .col {\r\nwidth: 200px !important; }\r\n.ie-browser .block-grid.four-up .col, [owa] .block-grid.four-up .col {\r\nwidth: 150px !important; }\r\n.ie-browser .block-grid.five-up .col, [owa] .block-grid.five-up .col {\r\nwidth: 120px !important; }\r\n.ie-browser .block-grid.six-up .col, [owa] .block-grid.six-up .col {\r\nwidth: 100px !important; }\r\n.ie-browser .block-grid.seven-up .col, [owa] .block-grid.seven-up .col {\r\nwidth: 85px !important; }\r\n.ie-browser .block-grid.eight-up .col, [owa] .block-grid.eight-up .col {\r\nwidth: 75px !important; }\r\n.ie-browser .block-grid.nine-up .col, [owa] .block-grid.nine-up .col {\r\nwidth: 66px !important; }\r\n.ie-browser .block-grid.ten-up .col, [owa] .block-grid.ten-up .col {\r\nwidth: 60px !important; }\r\n.ie-browser .block-grid.eleven-up .col, [owa] .block-grid.eleven-up .col {\r\nwidth: 54px !important; }\r\n.ie-browser .block-grid.twelve-up .col, [owa] .block-grid.twelve-up .col {\r\nwidth: 50px !important; }\r\n@media only screen and (min-width: 620px) {\r\n.block-grid {\r\nwidth: 100% !important; }\r\n.block-grid .col {\r\nvertical-align: top; }\r\n.block-grid .col.num12 {\r\nwidth: 600px !important; }\r\n.block-grid.mixed-two-up .col.num4 {\r\nwidth: 200px !important; }\r\n.block-grid.mixed-two-up .col.num8 {\r\nwidth: 400px !important; }\r\n.block-grid.two-up .col {\r\nwidth: 300px !important; }\r\n.block-grid.three-up .col {\r\nwidth: 200px !important; }\r\n.block-grid.four-up .col {\r\nwidth: 150px !important; }\r\n.block-grid.five-up .col {\r\nwidth: 120px !important; }\r\n.block-grid.six-up .col {\r\nwidth: 100px !important; }\r\n.block-grid.seven-up .col {\r\nwidth: 85px !important; }\r\n.block-grid.eight-up .col {\r\nwidth: 75px !important; }\r\n.block-grid.nine-up .col {\r\nwidth: 66px !important; }\r\n.block-grid.ten-up .col {\r\nwidth: 60px !important; }\r\n.block-grid.eleven-up .col {\r\nwidth: 54px !important; }\r\n.block-grid.twelve-up .col {\r\nwidth: 50px !important; } }\r\n@media (max-width: 620px) {\r\n.block-grid, .col {\r\nmin-width: 320px !important;\r\nmax-width: 100% !important;\r\ndisplay: block !important; }\r\n.block-grid {\r\nwidth: calc(100% - 40px) !important; }\r\n.col {\r\nwidth: 100% !important; }\r\n.col > div {\r\nmargin: 0 auto; }\r\nimg.fullwidth, img.fullwidthOnMobile {\r\nmax-width: 100% !important; }\r\n.no-stack .col {\r\nmin-width: 0 !important;\r\ndisplay: table-cell !important; }\r\n.no-stack.two-up .col {\r\nwidth: 50% !important; }\r\n.no-stack.mixed-two-up .col.num4 {\r\nwidth: 33% !important; }\r\n.no-stack.mixed-two-up .col.num8