px; padding-bottom: 10px;\">\r\n			<div style=\"font-size:12px;line-height:14px;color:#0D0D0D;font-family:\'Montserrat\', \'Trebuchet MS\', \'Lucida Grande\', \'Lucida Sans Unicode\', \'Lucida Sans\', Tahoma, sans-serif;text-align:left;\">\r\n			<p style=\"margin: 0;font-size: 14px;line-height: 17px;text-align: center\"><span style=\"font-size: 28px; line-height: 33px;\"><strong><span style=\"line-height: 33px; font-size: 28px;\">Hello</span></strong><span style=\"line-height: 33px; font-size: 28px;\">&nbsp;<strong>{{$name}},</strong></span></span></p>\r\n\r\n			<p style=\"margin: 0;font-size: 14px;line-height: 17px;text-align: center\"><br />\r\n			<span style=\"color: rgb(13, 13, 13); font-family: Montserrat, &quot;Trebuchet MS&quot;, &quot;Lucida Grande&quot;, &quot;Lucida Sans Unicode&quot;, &quot;Lucida Sans&quot;, Tahoma, sans-serif; font-size: 14px; text-align: center;\">Your instructor request has been approved successfully</span></p>\r\n			</div>\r\n			</div>\r\n			</div>\r\n\r\n			<div style=\"line-height:150%;color:#555555;font-family:\'Montserrat\', \'Trebuchet MS\', \'Lucida Grande\', \'Lucida Sans Unicode\', \'Lucida Sans\', Tahoma, sans-serif; padding-right: 10px; padding-left: 10px; padding-top: 10px; padding-bottom: 10px;\">\r\n			<div style=\"font-size:12px;line-height:18px;color:#555555;font-family:\'Montserrat\', \'Trebuchet MS\', \'Lucida Grande\', \'Lucida Sans Unicode\', \'Lucida Sans\', Tahoma, sans-serif;text-align:left;\">\r\n			<p style=\"margin: 0;font-size: 14px;line-height: 21px;text-align: center\">&nbsp;</p>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n			</div>\r\n\r\n			<div style=\"background-color:transparent; text-align: center;\">\r\n			<div class=\"block-grid three-up \" style=\"Margin: 0 auto;min-width: 320px;max-width: 600px;overflow-wrap: break-word;word-wrap: break-word;word-break: break-word;background-color: #0b0055; border-radius: 0 0 10px 10px; padding: 20px 0; \">\r\n			<div style=\"display: inline-block; vertical-align: middle;\">\r\n			<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" height=\"32\" style=\"border-collapse: collapse;\">\r\n				<tbody>\r\n					<tr>\r\n						<td><a href=\"{{$settingfacebook}}\" target=\"_blank\" title=\"Facebook\"><img alt=\"Facebook\" src=\"https://instrushare.vrinsoft.in/public/images/faceboo.png\" style=\"outline: none;text-decoration: none;-ms-interpolation-mode: bicubic;clear: both;display: block !important;border: none;height: auto;float: none;max-width: 32px !important\" title=\"Facebook\" width=\"32\" /> </a></td>\r\n						<td><a href=\"{{$settingtwitter}}\" target=\"_blank\" title=\"Twitter\"><img alt=\"Twitter\" src=\"https://instrushare.vrinsoft.in/public/images/twitte.png\" style=\"outline: none;text-decoration: none;-ms-interpolation-mode: bicubic;clear: both;display: block !important;border: none;height: auto;float: none;max-width: 32px !important\" title=\"Twitter\" width=\"32\" /> </a></td>\r\n						<td><a href=\"{{$settinginstagram}}\" target=\"_blank\" title=\"Instagram\"><img alt=\"Instagram\" src=\"https://instrushare.vrinsoft.in/public/images/instagra.png\" style=\"outline: none;text-decoration: none;-ms-interpolation-mode: bicubic;clear: both;display: block !important;border: none;height: auto;float: none;max-width: 32px !important\" title=\"Instagram\" width=\"32\" /> </a></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</div>\r\n\r\n			<div style=\"display: inline-block; vertical-align: middle; padding: 5px 18px; color: #fff; font-family: \'Montserrat\', \'Trebuchet MS\', \'Lucida Grande\', \'Lucida Sans Unicode\', \'Lucida Sans\', Tahoma, sans-serif; font-size: 14px;\"><span style=\"color: rgb(255, 255, 255); font-family: Montserrat, &quot;Trebuchet MS&quot;, &quot;Lucida Grande&quot;, &quot;Lucida Sans Unicode&quot;, &quot;Lucida Sans&quot;, Tahoma, sans-serif; font-size: 14px; text-align: center; background-color: rgb(0, 22, 69);\">Email:&nbsp;</span><span style=\"color: rgb(255, 255, 255); font-family: Montserrat, &quot;Trebuchet MS&quot;, &quot;Lucida Grande&quot;, &quot;Lucida Sans Unicode&quot;, &quot;Lucida Sans&quot;, Tahoma, sans-serif; font-size: 14px; text-align: center; background-color: rgb(0, 22, 69);\">{$supportemail}</span></div>\r\n			</div>\r\n			</div>\r\n\r\n			<div style=\"background-color:transparent;\">\r\n			<div class=\"block-grid \" style=\"Margin: 0 auto;min-width: 320px;max-width: 600px;overflow-wrap: break-word;word-wrap: break-word;word-break: break-word;background-color: transparent;\">\r\n			<div style=\"border-collapse: collapse;display: table;width: 100%;background-color:transparent;\">\r\n			<div class=\"col num12\" style=\"min-width: 320px;max-width: 600px;display: table-cell;vertical-align: top;\">\r\n			<div style=\"background-color: transparent; width: 100% !important;\">\r\n			<div style=\"border-top: 0px solid transparent; border-left: 0px solid transparent; border-bottom: 0px solid transparent; border-right: 0px solid transparent; padding-top:0px; padding-bottom:5px; padding-right: 0px; padding-left: 0px;\">\r\n			<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" class=\"divider\" style=\"border-collapse: collapse;table-layout: fixed;border-spacing: 0;mso-table-lspace: 0pt;mso-table-rspace: 0pt;vertical-align: top;min-width: 100%;-ms-text-size-adjust: 100%;-webkit-text-size-adjust: 100%\" width=\"100%\">\r\n				<tbody>\r\n					<tr style=\"vertical-align: top\">\r\n						<td class=\"divider_inner\" style=\"word-break: break-word;border-collapse: collapse !important;vertical-align: top;padding-right: 30px;padding-left: 30px;padding-top: 30px;padding-bottom: 30px;min-width: 100%;mso-line-height-rule: exactly;-ms-text-size-adjust: 100%;-webkit-text-size-adjust: 100%\">\r\n						<table align=\"center\" border=\"0\" cellpadding=\"0\" cellspacing=\"0\" class=\"divider_content\" style=\"border-collapse: collapse;table-layout: fixed;border-spacing: 0;mso-table-lspace: 0pt;mso-table-r