(3, 2, 'Wholesaler Invite Link', 'Invite Link', '<title></title>\r\n<meta charset=\"UTF-8\"><meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Outfit:wght@100;200;300;400;500;600;700;800;900&amp;display=swap\" rel=\"stylesheet\" />\r\n<table align=\"center\" cellpadding=\"0\" cellspacing=\"0\" width=\"800px\">\r\n	<tbody><!-- Top Image -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><img alt=\"top-image\" src=\"{{$graphic_image}}\" style=\"display: block;\" /></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Logo -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFF7D5\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 40px;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><a href=\"javascript:void(0)\" style=\"display: block;\" target=\"_blank\"><img alt=\"top-image\" src=\"{{$logo}}\" style=\"display: block;\" /> </a></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Details -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 32px 40px; border-bottom: 2px solid #F6F5EF;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\">\r\n						<h2 style=\"font-size: 42px; line-height: 60px; font-weight: 500; color: #000000; margin: 0; padding: 0 0 32px;\">Welcome !</h2>\r\n						</td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"left\"><!-- <h5 style=\"font-size: 24px; line-height: 36px; font-weight: 500; color: #000000; margin: 0; padding: 0 0 8px;\">Hello Olivia Doe,</h5> --><!-- <p style=\"font-size: 20px; line-height: 30px; font-weight: 300; letter-spacing: 0.04em; color: #000000; margin: 0; padding: 0 0 32px;\">Kindly Register to below link here.</p> --><span style=\"font-size: 18px; line-height: 27px; font-weight: 300; color: #000000; margin: 0; padding: 0 0 16px; display: block;\">Kindly Register to below link here.</span></td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"left\">\r\n						<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n							<tbody>\r\n								<tr>\r\n									<td align=\"left\"><span align=\"left\" style=\"font-size: 14px; line-height: 21px; font-weight: 300; color: #000000; display: inline-block; margin: 0 57px 0 0;\">Email :</span> <span align=\"left\" style=\"margin: 0; font-size: 16px; line-height: 24px; font-weight: 500; color: #000000; display: inline-block;\">{{$email}}</span></td>\r\n								</tr>\r\n								<tr>\r\n									<td height=\"16px\">&nbsp;</td>\r\n								</tr>\r\n								<tr>\r\n									<td align=\"left\">&nbsp;</td>\r\n								</tr>\r\n								<tr>\r\n									<td height=\"16px\">&nbsp;</td>\r\n								</tr>\r\n								<tr>\r\n									<td align=\"center\"><a href=\"{{$link}}\" style=\"padding: 8px 16px;font-weight: 400;font-size: 14px;line-height: 21px;text-transform: uppercase;color: #232B44;border: 1px solid #232B44;border-radius: 45px; text-decoration: none; display: inline-block;\">Click Here</a></td>\r\n								</tr>\r\n							</tbody>\r\n						</table>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Footer -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 32px 40px;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" style=\"padding: 0 0 22px;\"><span style=\"display: inline-block;\"><a href=\"{{$settingfacebook}}\" style=\"text-decoration: none; vertical-align: middle; margin: 0 23px 0 0; text-align: center; display: inline-block;\" target=\"_blank\"