"left\"><span style=\"font-size:14px;\"><span align=\"left\" style=\"line-height: 21px; font-weight: 300; color: rgb(0, 0, 0); display: inline-block; margin: 0px 45px 0px 0px;\">Postcode :</span> <span align=\"left\" style=\"margin: 0px; line-height: 24px; font-weight: 500; color: rgb(0, 0, 0); display: inline-block;\">{{$post_code}}</span></span></td>\r\n								</tr>\r\n								<tr>\r\n									<td height=\"16px\">&nbsp;</td>\r\n								</tr>\r\n								<tr>\r\n									<td align=\"left\"><span style=\"font-size:14px;\"><span align=\"left\" style=\"line-height: 21px; font-weight: 300; color: rgb(0, 0, 0); display: inline-block; margin: 0px 32px 0px 0px;\">Description :</span> <span align=\"left\" style=\"margin: 0px; line-height: 24px; font-weight: 500; color: rgb(0, 0, 0); display: inline-block;\">{{$description}}</span></span></td>\r\n								</tr>\r\n								<tr>\r\n									<td align=\"left\"><span style=\"font-size:14px;\"><span align=\"left\" style=\"line-height: 21px; font-weight: 300; color: rgb(0, 0, 0); display: inline-block; margin: 0px 32px 0px 0px;\">Quote Image :</span></span> <span align=\"left\" style=\"margin: 0; font-size: 16px; line-height: 24px; font-weight: 500; color: #000000; display: inline-block;\"><a href=\"{{$image_name}}\" target=\"_blank\"><img src=\"{{$image_name}}\" style=\"width: 50px; height: 50px; margin-bottom: -20px margin-top: 10px;\" title=\"Quote image\" /></a></span>\r\n									<p>&nbsp;</p>\r\n									</td>\r\n								</tr>\r\n								<tr>\r\n									<td height=\"16px\">\r\n									<h5 style=\"line-height: 36px; font-size: 24px; color: rgb(0, 0, 0); margin: 0px; padding: 0px 0px 8px;\"><span style=\"font-size:14px;\">Best regards,<br />\r\n									Trade25 team</span></h5>\r\n									</td>\r\n								</tr>\r\n							</tbody>\r\n						</table>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Footer -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\