	<p style=\"font-size: 14px; line-height: 21px; font-weight: 300; color: #000000; margin: 0;\">Get in touch with us at<a href=\"mailto:info@trade25.com\" style=\"margin: 0; font-size: 16px; line-height: 24px; font-weight: 500; color: #232B44; margin-left: 4px; display: inline-block; text-decoration: none;\">info@trade25.com</a></p>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Bottom Image -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><img alt=\"top-image\" src=\"{{$graphic_image}}\" style=\"display: block;\" /></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>', 1, NULL, '2023-01-18 06:38:33', '2023-08-16 08:54:41'),
