(15, 2, 'Forgot OTP verification', 'OTP verification', '<title></title>\r\n<meta charset=\"UTF-8\"><meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n<link href=\"https://fonts.googleapis.com/css2?family=Outfit:wght@100;200;300;400;500;600;700;800;900&amp;display=swap\" rel=\"stylesheet\" />\r\n<table align=\"center\" cellpadding=\"0\" cellspacing=\"0\" width=\"800px\">\r\n	<tbody><!-- Top Image -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><img alt=\"top-image\" src=\"{{$graphic_image}}\" style=\"display: block;\" /></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Logo -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFF7D5\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 40px;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><a href=\"javascript:void(0)\" style=\"display: block;\" target=\"_blank\"><img alt=\"top-image\" src=\"{{$logo}}\" style=\"display: block;\" /> </a></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Details -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 32px 40px; border-bottom: 2px solid #F6F5EF;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\">\r\n						<h2 style=\"font-size: 42px; line-height: 60px; font-weight: 500; color: #000000; margin: 0; padding: 0 0 32px;\">Forgot password?&nbsp;</h2>\r\n						</td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"left\">\r\n						<h5 style=\"font-size: 24px; line-height: 36px; font-weight: 500; color: #000000; margin: 0; padding: 0 0 8px;\"><span style=\"font-size:20px;\">Hello</span> <span style=\"font-size:18px;\">{{$name}}</span></h5>\r\n\r\n						<p style=\"font-size: 20px; line-height: 30px; font-weight: 300; letter-spacing: 0.04em; color: #000000; margin: 0; padding: 0 0 32px;\"><span style=\"font-size: 20px; letter-spacing: 0.8px;\"><span style=\"font-size:14px;\">Thank you for connecting with Trade25. It seems like you forgot your password. if this is true, don&#39;t worry! use the below code to set up a new password.</span><br />\r\n						<br />\r\n						<span style=\"font-size:14px;\">OTP to verify:</span></span></p>\r\n						</td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"left\">\r\n						<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n							<tbody>\r\n								<tr>\r\n									<td align=\"left\"><span style=\"font-size:20px;\"><span style=\"font-size:14px;\"><span align=\"left\" style=\"line-height: 21px; font-weight: 300; color: rgb(0, 0, 0); display: inline-block; margin: 0px 32px 0px 0px;\">OTP :</span> <span align=\"left\" style=\"margin: 0px; line-height: 24px; font-weight: 500; color: rgb(0, 0, 0); display: inline-block;\">{{$otp}}</span></span><br />\r\n									<br />\r\n									<span style=\"font-size:14px;\">Best regards,<br />\r\n									Trade25 team</span></span></td>\r\n								</tr>\r\n							</tbody>\r\n						</table>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Footer -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" style=\"padding: 32px 40px;\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" style=\"padding: 0 0 22px;\"><span style=\"display: inline-block;\"><a href=\"{{$settingfacebook}}\" style=\"text-decoration: none; vertical-align: middle; margin: 0 23px 0 0; text-align: center; display: inline-block;\" target=\"_blank\"><img alt=\"linkedIn\" src=\"{{$facebook_logo}}\" style=\"vertical-align: middle;\" /> </a> <a href=\"{{$settingtwitter}}\" style=\"text-decoration: none; vertical-align: middle; margin: 0 23px 0 0; text-align: center; display: inline-block;\" target=\"_blank\"> <img alt=\"twitter\" src=\"{{$in_logo}}\" style=\"vertical-align: middle;\" /> </a> <a href=\"{{$settinginstagram}}\" style=\"text-decoration: none; vertical-align: middle; margin: 0; text-align: center; display: inline-block;\" target=\"_blank\"> <img alt=\"instagram\" src=\"{{$insta_logo}}\" style=\"vertical-align: middle;\" /> </a> </span></td>\r\n					</tr>\r\n					<tr>\r\n						<td align=\"center\">\r\n						<p style=\"font-size: 14px; line-height: 21px; font-weight: 300; color: #000000; margin: 0;\">Get in touch with us at<a href=\"mailto:info@trade25.com\" style=\"margin: 0; font-size: 16px; line-height: 24px; font-weight: 500; color: #232B44; margin-left: 4px; display: inline-block; text-decoration: none;\">info@trade25.com</a></p>\r\n						</td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n		<!-- Bottom Image -->\r\n		<tr>\r\n			<td align=\"center\" bgcolor=\"#FFFFFF\" valign=\"top\">\r\n			<table cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\r\n				<tbody>\r\n					<tr>\r\n						<td align=\"center\" valign=\"top\"><img alt=\"top-image\" src=\"{{$graphic_image}}\" style=\"display: block;\" /></td>\r\n					</tr>\r\n				</tbody>\r\n			</table>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>', 1, NULL, '2023-01-18 04:45:27', '2023-08-16 08:59:06');
