(57, '640733b8ecf13', 'PRO000057', 15, 'Tool Kit Ratchet Sets', '<ul class=\"a-unordered-list a-vertical a-spacing-mini\" style=\"box-sizing: border-box; margin: 0px 0px 0px 18px; color: rgb(15, 17, 17); padding-right: 0px; padding-left: 0px; font-family: &quot;Amazon Ember&quot;, Arial, sans-serif; font-size: 14px;\">\r\n	<li style=\"box-sizing: border-box; list-style: disc; overflow-wrap: break-word; margin: 0px;\"><span class=\"a-list-item\" style=\"box-sizing: border-box;\">94 Piece Tool set is the perfect tool kit.</span></li>\r\n	<li style=\"box-sizing: border-box; list-style: disc; overflow-wrap: break-word; margin: 0px;\"><span class=\"a-list-item\" style=\"box-sizing: border-box;\">1/2&quot;&quot;, 3/8&quot; &amp; 1/4&quot; drive, chrome vanadium standard &amp; deep sockets.</span></li>\r\n	<li style=\"box-sizing: border-box; list-style: disc; overflow-wrap: break-word; margin: 0px;\"><span class=\"a-list-item\" style=\"box-sizing: border-box;\">Contains a carefully selected assortment of hand tools needed for most industrial, mechanical, and consumer applications.</span></li>\r\n	<li style=\"box-sizing: border-box; list-style: disc; overflow-wrap: break-word; margin: 0px;\"><span class=\"a-list-item\" style=\"box-sizing: border-box;\">All tools contained in a sturdy, folding plastic case for easy storage and transport It comes in a small compact case so you can easily store it once you have finished using it.</span></li>\r\n	<li style=\"box-sizing: border-box; list-style: disc; overflow-wrap: break-word; margin: 0px;\"><span class=\"a-list-item\" style=\"box-sizing: border-box;\">SNE</span></li>\r\n</ul>', 'SNE_94 in 1 Tool Kit Ratchet Sets 1/2\" 1/4\" Socket Wrenches Set Screwdriver Mechanics Toolkit', 28, '16781935928762.jpg', NULL, '16781935924483.pdf', 6019, 5000, 0, 83, 1, NULL, NULL, '2023-03-07 12:53:12', '2023-08-11 11:58:56'),
(58, '640734a7c6f7f', 'PRO000058', 15, 'rolson Electrical Repair', '<div class=\"_3k-BhJ\" style=\"box-sizing: border-box; margin: 0px; padding: 24px 24px 34px; border-top: 1px solid rgb(240, 240, 240); font-size: 14px; color: rgb(33, 33, 33); font-family: Roboto, Arial, sans-serif;\">\r\n<div class=\"flxcaE\" style=\"box-sizing: border-box; margin: 0px; padding: 0px 0px 16px; font-size: 18px; white-space: nowrap; line-height: 1.4;\">Important Note</div>\r\n\r\n<table class=\"_14cfVK\" style=\"margin: 0px; padding: 0px; width: 738.438px; border-collapse: collapse;\">\r\n	<tbody style=\"box-sizing: border-box; margin: 0px; padding: 0px;\">\r\n		<tr class=\"_1s_Smc row\" style=\"box-sizing: border-box; margin: 0px; padding: 0px; display: flex; flex-flow: row wrap; width: 738.438px;\">\r\n			<td class=\"URwL2w col col-12-12\" style=\"box-sizing: border-box; margin: 0px; padding: 0px; width: 738.438px; display: inline-block; vertical-align: top; line-height: 1.4; word-break: break-word;\">\r\n			<ul style=\"box-sizing: border-box; margin: 0px; padding-right: 0px; padding-left: 0px;\">\r\n				<li class=\"_21lJbe\" style=\"box-sizing: border-box; margin: 0px; padding: 0px; list-style: none;\">You, the customer hereby represent and undertake that you are of legal age for purchase and use of this product. You undertake that you will use the product for domestic, and/or agricultural purposes only and in a safe and legal manner, consistent with all applicable laws, safety rules, and good common sense. Further, you represent that you will take such steps as may be reasonably necessary or required by applicable law to keep the product out of the hands of minors, untrained and/or unsound mind individuals. Flipkart shall not assume any consequences, loss, damage or injury, that may arise from the violent or illegal use, or misuse of the product sold by the independent Sellers on the Flipkart platform. It is the responsibility of the customer to handle the product with due care and its intended and legitimate use as a tool. Flipkart does not represent or warrant that the customer may legally purchase, own, or possess the product. Please check the laws and regulations outlined by Law Enforcement Agencies in your local jurisdiction before purchasing and keeping the product in possession.</li>\r\n			</ul>\r\n			</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n</div>\r\n\r\n<div class=\"_3k-BhJ\" style=\"box-sizing: border-box; margin: 0px; padding: 24px 24px 34px; border-top: 1px solid rgb(240, 240, 240); font-size: 14px; color: rgb(33, 33, 33); font-family: Roboto, Arial, sans-serif;\">&nbsp;</div>', 'Keep this Rolson Electrical Tool Kit handy so that you do not have to call for professional help for every small electrical repair work. Fixing loose wire terminals, installing new cable or electrical connections and crimping wires can be done with this electrical repair tool kit.\r\n\r\nInsulated screwdrivers, mains tester, wire cutter, crimp tool, PVC tape and other accessories are included in this tool kit to make it functional for those who do electrical repair work by themselves. You can be assured of the quality of items in this set as they are manufactured by Rolson, which is a trusted producer of tools and accessories.', 28, '16781938314364.jpeg', NULL, '16781938313497.pdf', 8015, 15, 0, 26, 1, 1, 1, '2023-03-07 12:57:11', '2023-08-11 09:27:18'),
(59, '63f73d62f064a', 'PRO000059', 47, 'Electrical Repair test', '<h6 style=\"box-sizing: border-box; margin: 0px 0px 12px; line-height: 24px; font-size: 16px; color: rgb(0, 0, 0); font-family: Outfit, sans-serif;\">Information</h6>\r\n\r\n<ul class=\"common-list\" style=\"box-sizing: border-box; padding-right: 0px; padding-left: 0px; margin: 0px 0px 16px; list-style-type: none; max-width: 628px; color: rgb(63, 55, 77); font-family: Outfit, sans-serif; font-size: 14px;\">\r\n	<li style=\"box-sizing: border-box; font-size: 16px; line-height: 24px; color: rgb(80, 80, 80); position: relative; padding-left: 16px;\">A durable, non yellowing, water based interior/exterior enamel that is low odour and easy water wash up.</li>\r\n</ul>\r\n\r\n<h6 style=\"box-sizing: border-box; margin: 0px 0px 12px; line-height: 24px; font-size: 16px; color: rgb(0, 0, 0); font-family: Outfit, sans-serif;\">Features</h6>\r\n\r\n<ul class=\"common-list\" style=\"box-sizing: border-box; padding-right: 0px; padding-left: 0px; margin: 0px 0px 16px; list-style-type: none; max-width: 628px; color: rgb(63, 55, 77); font-family: Outfit, sans-serif; font-size: 14px;\">\r\n	<li style=\"box-sizing: border-box; font-size: 16px; line-height: 24px; color: rgb(80, 80, 80); position: relative; padding-left: 16px;\">Water based</li>\r\n	<li style=\"box-sizing: border-box; font-size: 16px; line-height: 24px; color: rgb(80, 80, 80); position: relative; padding-left: 16px;\">Fast drying, 2 hour dry time</li>\r\n	<li style=\"box-sizing: border-box; font-size: 16px; line-height: 24px; color: rgb(80, 80, 80); position: relative; padding-left: 16px;\">Available in 1L, 2L, 4L, 10L</li>\r\n	<li style=\"box-sizing: border-box; font-size: 16px; line-height: 24px; color: rgb(80, 80, 80); position: relative; padding-left: 16px;\">Available in White, Deep, Ultra Deep and Extra Bright bases</li>\r\n</ul>\r\n\r\n<h6 style=\"box-sizing: border-box; margin: 0px 0px 12px; line-height: 24px; font-size: 16px; color: rgb(0, 0, 0); font-family: Outfit, sans-serif;\">Warranty</h6>\r\n\r\n<p style=\"box-sizing: border-box; margin: 0px 0px 15px; font-size: 16px; line-height: 24px; color: rgb(105, 95, 112); max-width: 628px; font-family: Outfit, sans-serif;\">All surfaces must be thoroughly cleaned and free of all loose dirt, dust, grease, loose or flaking paint, and loose surface plaster. Efflorescence or mould on masonry or concrete surfaces must be treated. Flatten gloss surfaces by thoroughly sanding and wipe clean with a damp cloth, then apply primer, sealer or undercoat as required. Do not sand between coats.</p>\r\n\r\n<h6 style=\"box-sizing: border-box; margin: 0px 0px 12px; line-height: 24px; font-size: 16px; color: rgb(0, 0, 0); font-family: Outfit, sans-serif;\">Uses</h6>\r\n\r\n<p style=\"box-sizing: border-box; margin: 0px 0px 15px; font-size: 16px; line-height: 24px; color: rgb(105, 95, 112); max-width: 628px; font-family: Outfit, sans-serif;\">Dulux Aquanamel is a waterbased interior/exterior enamel that dries to a chip resistant, tough finish. Dulux Aquanamel can be used in many of the areas that traditional solvent based enamels are used, with all the time saving benefits of a water based paint. Dulux Aquanamel is non-yellowing and resists chipping. Dulux Aquanamel is highly recommended for doors, architraves, skirting boards, windows, timber trim and walls and is ideal for bathrooms, kitchens and laundries.</p>', 'Electrical Repair Description', 28, '16781933258395.png', NULL, '16771474902696.pdf', 650, 256, 0, 46, 1, NULL, NULL, '2023-02-23 04:48:10', '2023-08-11 11:24:41');
