(73, '642e3a1d3f3b0', 'PRO000073', 128, 'Solagard Gloss', '<p style=\"box-sizing: border-box; text-rendering: optimizelegibility; -webkit-font-smoothing: antialiased; margin-top: 0px; margin-bottom: 1rem; line-height: 1.25rem; color: rgb(3, 3, 4); font-family: Gotham-Book, &quot;sans-serif&quot;; font-size: 16px;\">Solagard Gloss is a tough and durable exterior paint which offers protection for your home in any weather or climate.</p>\r\n\r\n<p class=\"mb-2 font-weight-bold\" style=\"box-sizing: border-box; text-rendering: optimizelegibility; -webkit-font-smoothing: antialiased; margin-top: 0px; line-height: 1.25rem; color: rgb(3, 3, 4); font-family: Gotham-Book, &quot;sans-serif&quot;; font-size: 16px; margin-bottom: 0.5rem !important; font-weight: 700 !important;\">Features &amp; Benefits:</p>\r\n\r\n<ul style=\"box-sizing: border-box; text-rendering: optimizelegibility; -webkit-font-smoothing: antialiased; margin-top: 0px; margin-bottom: 5px; padding-left: 1rem; color: rgb(3, 3, 4); font-family: Gotham-Book, &quot;sans-serif&quot;; font-size: 16px;\">\r\n	<li style=\"box-sizing: border-box; text-rendering: optimizelegibility; -webkit-font-smoothing: antialiased;\">25 Year Warranty.</li>\r\n	<li style=\"box-sizing: border-box; text-rendering: optimizelegibility; -webkit-font-smoothing: antialiased;\">Lasting Flexibility.</li>\r\n	<li style=\"box-sizing: border-box; text-rendering: optimizelegibility; -webkit-font-smoothing: antialiased;\">Resists Chalking &amp; Fading.</li>\r\n	<li style=\"box-sizing: border-box; text-rendering: optimizelegibility; -webkit-font-smoothing: antialiased;\">Apply in temperatures as low as 5&deg;C.</li>\r\n	<li style=\"box-sizing: border-box; text-rendering: optimizelegibility; -webkit-font-smoothing: antialiased;\">Inhibits Mould and Mildew.</li>\r\n	<li style=\"box-sizing: border-box; text-rendering: optimizelegibility; -webkit-font-smoothing: antialiased;\">Self Priming.</li>\r\n</ul>', 'Solagard Gloss White 4L', 26, '16807511334622.jpg', NULL, '16807511338782.pdf', 110.1, 94.93, 0, 2, 1, 1, 1, '2023-04-06 03:18:53', '2023-08-02 10:22:48');
